import React, { useEffect, useMemo, useState, useCallback, useRef } from 'react';
import { Box, Button, Divider, InputBase, Popover } from '@mui/material';
import { Search as SearchIcon } from '@mui/icons-material';
import CalendarIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Calendar.js";
import SettingsIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Settings.js";
import AddIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Add.js";
import EditIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Edit.js";
import TrashIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Trash.js";
import FAWErrorBoundary from '../../errorHandling/FAWErrorBoundary';
import FAWConfirmDialogue from '../../FAWConfirmDialogue';
// import FAWAgGrid from '../../FAWAgGrid'; // Commented out - migrating to FAWTable
import FAWTable from '../../FAWTable/FAWTable';
import { useGridApiRef } from '@mui/x-data-grid-pro';
import FAWTypography from '../../FAWTypography';
import FAWButton from '../../FAWButton';
import FAWInput from '../../FAWInput';
import FAWRadioGroup from '../../FAWRadioGroup';
import { useWorkflowGridState } from '../hooks/useWorkflowGridState';
import { useWorkflowGridHandlers } from '../hooks/useWorkflowGridHandlers';
import { colors } from '../../../../utils/designTokens';
import '../styles/workflow-grid.css';

/**
 * WorkflowGrid - Complete workflow grid component with integrated agGrid
 * Handles data loading based on tabId, time period filtering, filter management, and workflow buttons
 * 
 * @param {Object} props
 * @param {String} props.tabId - Tab ID to load data for (e.g., 'workflow_filter_5775')
 * @param {Array} props.columnDefs - Grid column definitions
 * @param {Array} props.actions - Grid row actions
 * @param {Array} props.actionIcons - Action icons for toolbar
 * @param {Function} props.onCreateFilterClick - Handler for create filter button clicks
 * @param {Function} props.onGridReady - Callback when grid is ready
 * @param {Function} props.onFirstDataRendered - Callback when first data is rendered
 * @param {Object} props.gridOptions - Additional grid options
 * @param {String} props.filterType - Filter type (SecurimateWorkItemFilterGroup or SecurimateWorkItemTaskFilterGroup)
 */
const WorkflowGrid = ({
  tabId,
  columnDefs = [],
  actions = [],
  actionIcons = [],
  onCreateFilterClick = null,
  onGridReady = null,
  onFirstDataRendered = null,
  gridOptions = {},
  filterData = [],
  initialTimePeriod = 'all',
  searchPlaceholder = 'Search by any field',
  noRowsMessage = 'No workflows found.',
  workflowFilterDropdown = null,
  filterType = 'SecurimateWorkItemFilterGroup',
  ...otherProps
}) => {
  const [rowData, setRowData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [deleteConfirm, setDeleteConfirm] = useState({ open: false, filter: null, onConfirm: null });
  const gridContainerRef = useRef(null);
  const manageFiltersButtonRef = useRef(null);
  const timePeriodButtonRef = useRef(null);

  // Fetch data based on tabId
    useEffect(() => {
    if (!tabId) {
      console.warn('[WorkflowGrid] No tabId provided');
      setLoading(false);
      return;
    }

    const fetchData = async () => {
      try {
        setLoading(true);
        setError(null);        
        // Method 1: Try to get data from global window object (populated by Razor views)
        // Format: window.workflowRowData[tabId] or window.taskRowData[tabId] or window['workflowRowData_' + tabId]
        if (typeof window !== 'undefined') {
          // Check workflowRowData first (for workflows)
          if (window.workflowRowData && window.workflowRowData[tabId]) {
            const data = window.workflowRowData[tabId];
            
            setRowData(Array.isArray(data) ? data : []);
            setLoading(false);
            return;
          }
          
          // Check taskRowData (for tasks)
          if (window.taskRowData && window.taskRowData[tabId]) {
            const data = window.taskRowData[tabId];
            setRowData(Array.isArray(data) ? data : []);
            setLoading(false);
            return;
          }
          
          // Alternative: Check for tabId-specific global variable
          const tabDataVar = 'workflowRowData_' + tabId.replace(/[^a-zA-Z0-9]/g, '_');
          if (window[tabDataVar]) {
            const data = window[tabDataVar];
            setRowData(Array.isArray(data) ? data : []);
            setLoading(false);
            return;
          }
          
          // Alternative: Check for task-specific tabId variable
          const taskTabDataVar = 'taskRowData_' + tabId.replace(/[^a-zA-Z0-9]/g, '_');
          if (window[taskTabDataVar]) {
            const data = window[taskTabDataVar];
            setRowData(Array.isArray(data) ? data : []);
            setLoading(false);
            return;
          }
        }
        
        // Method 2: Try to find data in the DOM via data attributes
        const container = document.querySelector(`[data-tab-id="${tabId}"]`);
        if (container && container.dataset.rowData) {
          try {
            const data = JSON.parse(container.dataset.rowData);
            setRowData(Array.isArray(data) ? data : []);
            setLoading(false);
            return;
          } catch (e) {
            console.warn('[WorkflowGrid] Failed to parse rowData from data attribute:', e);
          }
        }
        
        // Method 3: Try to find grid container and extract data from it
        // This matches the pattern used in Razor views where gridId is derived from tabId
        const gridId = tabId.replace('workflow_filter_', '').replace('_tab', '');
        const gridContainer = document.getElementById('atlas-grid-' + gridId);
        if (gridContainer && gridContainer.dataset.rowData) {
          try {
            const data = JSON.parse(gridContainer.dataset.rowData);
            setRowData(Array.isArray(data) ? data : []);
            setLoading(false);
            return;
          } catch (e) {
            console.warn('[WorkflowGrid] Failed to parse rowData from grid container:', e);
          }
        }
        
        // Method 4: If rowData prop is provided directly, use it
        if (otherProps.rowData && Array.isArray(otherProps.rowData)) {
          setRowData(otherProps.rowData);
          setLoading(false);
          return;
        }
        
        // If no data found, use empty array
        console.warn('[WorkflowGrid] No data found for tabId:', tabId, '- using empty array');
        setRowData([]);
        setLoading(false);
      } catch (err) {
        console.error('[WorkflowGrid] Error fetching data for tabId:', tabId, err);
        setError(err.message || 'Failed to load data');
        setLoading(false);
      }
    };

    fetchData();
  }, [tabId, otherProps.rowData]);

  // Use custom hooks for state management and handlers
  const state = useWorkflowGridState({
    rowData,
    filterData,
    initialTimePeriod
  });
  
  const handlers = useWorkflowGridHandlers({
    rowData,
    onRowDataChange: (newFilteredData) => {
      // Update local state when filtered data changes
      // This is handled by the state hook, but we can add additional logic here if needed
    },
    onCreateFilterClick,
    setFilteredRowData: state.setFilteredRowData,
    setSelectedTimePeriod: state.setSelectedTimePeriod,
    setFilters: state.setFilters,
    filters: state.filters,
    setTimePeriodAnchorEl: state.setTimePeriodAnchorEl,
    setManageFiltersAnchorEl: state.setManageFiltersAnchorEl,
    setTimePeriodSearch: state.setTimePeriodSearch,
    filterDataByTimePeriod: state.filterDataByTimePeriod,
    timePeriodSearch: state.timePeriodSearch,
    filterType: filterType,
    onShowDeleteConfirm: (filter, performDelete) => {
      setDeleteConfirm({ open: true, filter, onConfirm: performDelete });
    }
  });

  // Render workflow toolbar component with time period popup
  const workflowActionsComponent = useMemo(() => {
    return (
      <Box sx={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
        {/* Time Period Button with Popover */}
        <Box 
          className="atlas-aggrid-timeperiod-filter" 
          sx={{ position: 'relative', display: 'inline-block' }}
        >
          <FAWButton
            ref={timePeriodButtonRef}
            variant="text"
            onClick={(e) => {
              const anchorElement = timePeriodButtonRef.current || e.currentTarget;
              state.setTimePeriodAnchorEl(anchorElement);
            }}
            startIcon={<CalendarIcon size="sm" />}
            size="small"
          >
            Time period: {state.timePeriodOptions.find(opt => opt.value === state.selectedTimePeriod)?.label || 'All'}
          </FAWButton>
          
          <Popover
            open={Boolean(state.timePeriodAnchorEl)}
            anchorEl={state.timePeriodAnchorEl || timePeriodButtonRef.current}
            onClose={() => {
              handlers.handleTimePeriodClose();
              state.setTimePeriodSearch('');
            }}
            anchorOrigin={{
              vertical: 'bottom',
              horizontal: 'left',
            }}
            transformOrigin={{
              vertical: 'top',
              horizontal: 'left',
            }}
            disableAutoFocus
            disableEnforceFocus
            disableRestoreFocus
            PaperProps={{
              sx: {
                backgroundColor: colors.background.default,
                borderRadius: '8px',
                boxShadow: '0px 0px 2px 0px rgba(0,0,0,0.1), 0px 8px 16px 0px rgba(0,0,0,0.1)',
                minWidth: '280px',
                maxWidth: '300px',
                marginTop: '4px',
                border: 'none',
                overflow: 'hidden',
                zIndex: 1300,
                padding: '0 !important'
              }
            }}
            BackdropProps={{
              sx: {
                backgroundColor: 'transparent'
              }
            }}
          >
            <Box sx={{ 
              backgroundColor: colors.background.default,
              display: 'flex',
              flexDirection: 'column',
              overflow: 'hidden'
            }}>
              {/* Search Input */}
              <Box sx={{ 
                display: 'flex',
                flexDirection: 'column',
                gap: 0,
                width: '100%',
                padding: '8px 12px'
              }}>
                <FAWInput
                  placeholder="Search"
                  value={state.timePeriodSearch || ''}
                  fullWidth
                  InputProps={{
                    startAdornment: (
                      <SearchIcon sx={{ color: colors.type.secondary, fontSize: '20px', mr: 1 }} />
                    )
                  }}
                  onChange={(e) => {
                    e.stopPropagation();
                    const value = e.target.value;
                    state.setTimePeriodSearch(value);
                  }}
                  onClick={(e) => {
                    e.stopPropagation();
                  }}
                  onFocus={(e) => {
                    e.stopPropagation();
                  }}
                  onKeyDown={(e) => {
                    e.stopPropagation();
                  }}
                  onMouseDown={(e) => {
                    e.stopPropagation();
                  }}
                />
                <Divider sx={{ mt: 1 }} />
              </Box>
              
              {/* Radio Options */}
              <Box sx={{ 
                maxHeight: '300px',
                overflowY: 'auto'
              }}>
                <FAWRadioGroup
                  id="time-period-radio-group"
                  options={state.filteredTimePeriodOptions || state.timePeriodOptions}
                  value={state.selectedTimePeriod}
                  onChange={(e) => {
                    handlers.handleTimePeriodChange(e);
                    state.setTimePeriodAnchorEl(null);
                    state.setTimePeriodSearch('');
                  }}
                  sx={{ 
                    width: '100%',
                    '& .MuiFormControl-root': {
                      width: '100%',
                    },
                    '& .MuiFormGroup-root': {
                      gap: 0,
                    },
                    '& .MuiFormControlLabel-root': {
                      margin: 0,
                      padding: '12px',
                      width: '100%',
                      '&:hover': {
                        backgroundColor: colors.background.secondary,
                      },
                    },
                  }}
                  labelSx={{
                    fontWeight: '400 !important',
                    fontSize: '16px !important',
                  }}
                />
              </Box>
            </Box>
          </Popover>
        </Box>

        {/* Create Filter Button */}
        {onCreateFilterClick && (
          <FAWButton
            variant="text"
            onClick={handlers.handleCreateFilterClick}
            startIcon={<AddIcon size="sm" />}
            size="small"
          >
            Create a new filter
          </FAWButton>
        )}

        {/* Manage Filters Button with Popover */}
        <Box 
          className="atlas-aggrid-manage-filters" 
          sx={{ position: 'relative', display: 'inline-block' }}
        >
          <FAWButton
            ref={manageFiltersButtonRef}
            variant="text"
            onClick={(e) => {
              const anchorElement = manageFiltersButtonRef.current || e.currentTarget;
              handlers.handleManageFiltersClick({ currentTarget: anchorElement });
            }}
            startIcon={<SettingsIcon size="sm" />}
            size="small"
          >
            Manage filters
          </FAWButton>
          
          <Popover
            open={Boolean(state.manageFiltersAnchorEl)}
            anchorEl={state.manageFiltersAnchorEl || manageFiltersButtonRef.current}
            onClose={handlers.handleManageFiltersClose}
            anchorOrigin={{
              vertical: 'bottom',
              horizontal: 'left',
            }}
            transformOrigin={{
              vertical: 'top',
              horizontal: 'left',
            }}
            disableAutoFocus
            disableEnforceFocus
            disableRestoreFocus
            PaperProps={{
              sx: {
                backgroundColor: colors.background.default,
                borderRadius: '8px',
                boxShadow: '0px 0px 2px 0px rgba(0,0,0,0.1), 0px 8px 16px 0px rgba(0,0,0,0.1)',
                minWidth: '480px',
                maxWidth: '480px',
                marginTop: '4px',
                border: 'none',
                overflow: 'hidden',
                zIndex: 1300
              }
            }}
            BackdropProps={{
              sx: {
                backgroundColor: 'transparent'
              }
            }}
          >
            <Box sx={{ 
              backgroundColor: colors.background.default,
              display: 'flex',
              flexDirection: 'column',
              overflow: 'hidden',
              padding: '0 16px'
            }}>
              {/* Header */}
              <Box sx={{ 
                display: 'flex',
                flexDirection: 'column',
                gap: 0,
                paddingTop: '16px',
                paddingBottom: '8px'
              }}>
                <FAWTypography variant="h6" sx={{ fontWeight: 600, fontSize: '18px', color: colors.type.default }}>
                  Manage filters
                </FAWTypography>
              </Box>

              {/* "Filters" header fixed above the list � not inside scroll so it never overlaps */}
              <Box sx={{
                borderBottom: `1px solid #DADADA`,
                padding: '12px 0',
                flexShrink: 0
              }}>
                <FAWTypography variant="caption" sx={{ fontWeight: 600, fontSize: '12px', color: `${colors.type.default} !important` }}>
                  Filters
                </FAWTypography>
              </Box>

              {/* Scrollable list only � scroll does not go above the "Filters" line */}
              <Box sx={{ 
                display: 'flex',
                flexDirection: 'column',
                gap: 0,
                maxHeight: '400px',
                overflowY: 'auto',
                paddingRight: '8px',
                flex: '1 1 auto',
                minHeight: 0
              }}>
                {state.filters.map((filter) => (
                  <Box key={filter.id} sx={{
                    display: 'flex',
                    gap: '16px',
                    alignItems: 'center',
                    padding: '12px 0',
                    minWidth: 0
                  }}>
                    {/* Filter Info */}
                    <Box sx={{ flex: 1 }}>
                      <FAWTypography variant="body2" sx={{ fontWeight: 400, fontSize: '14px', color: colors.type.default }}>
                        {filter.name} ({filter.count})
                      </FAWTypography>
                    </Box>

                    {/* Action Buttons � flexShrink: 0 so they stay visible and don't overlap text */}
                    <Box sx={{ display: 'flex', gap: '8px', flexShrink: 0 }}>
                      <Button 
                        variant="text" 
                        size="small" 
                        disabled={!filter.actualId || parseInt(filter.actualId, 10) <= 0 || filter.name === 'All Workflows'}
                        onClick={(e) => {
                          e.stopPropagation();
                          e.preventDefault();
                          handlers.handleFilterEdit(filter.id);
                        }}
                        sx={{ 
                          minWidth: 'auto', 
                          padding: '4px',
                          '&:hover': {
                            backgroundColor: 'transparent'
                          }
                        }}
                      >
                        <EditIcon size="sm" style={{ color: (!filter.actualId || parseInt(filter.actualId, 10) <= 0 || filter.name === 'All Workflows') ? colors.type.tertiary : colors.type.default }} />
                      </Button>
                      <Button 
                        variant="text" 
                        size="small" 
                        disabled={filter.enabled || !filter.actualId || filter.name === 'All Workflows'}
                        onClick={(e) => {
                          e.stopPropagation();
                          e.preventDefault();
                          if (!filter.enabled && filter.actualId && filter.name !== 'All Workflows') {
                            handlers.handleFilterDelete(filter.id);
                          }
                        }}
                        sx={{ 
                          minWidth: 'auto', 
                          padding: '4px',
                          '&:hover': {
                            backgroundColor: 'transparent'
                          }
                        }}
                      >
                        <TrashIcon 
                          size="sm" 
                          style={{ 
                            color: (filter.enabled || !filter.actualId || filter.name === 'All Workflows') ? colors.type.tertiary : colors.type.default 
                          }} 
                        />
                      </Button>
                    </Box>
                  </Box>
                ))}
              </Box>

              {/* Footer */}
              <Box sx={{ 
                display: 'flex',
                justifyContent: 'flex-end',
                paddingTop: '16px',
                paddingBottom: '16px',
                borderTop: `1px solid ${colors.ui.border.static}`
              }}>
                <FAWButton variant="contained" size="small" onClick={handlers.handleManageFiltersClose}>Close</FAWButton>
              </Box>
            </Box>
          </Popover>
        </Box>
      </Box>
    );
  }, [
    state.selectedTimePeriod,
    state.filters,
    state.timePeriodAnchorEl,
    state.manageFiltersAnchorEl,
    state.timePeriodSearch,
    state.filteredTimePeriodOptions,
    state.timePeriodOptions,
    handlers,
    onCreateFilterClick
  ]);

  // FAWTable API ref for external access
  const apiRef = useGridApiRef();

  // Adapt columnDefs for FAWTable - handle onClick compatibility (params.data vs params.row)
  const columns = useMemo(() => {
    if (!columnDefs || !Array.isArray(columnDefs)) {
      return [];
    }
    
    return columnDefs.map((col) => {
      // If column has onClick that expects params.data format, wrap it
      if (col.onClick && col.type === 'link') {
        return {
          ...col,
          onClick: (params, e) => {
            // FAWTable provides params.row, but legacy code expects params.data
            const adaptedParams = {
              ...params,
              data: params.row,
              row: params.row
            };
            col.onClick(adaptedParams, e);
          }
        };
      }
      return col;
    });
  }, [columnDefs]);

  // Handle grid ready callback
  const handleGridReady = useCallback((params) => {
    if (onGridReady) {
      onGridReady(params);
    }
    // Store grid API for external access
    if (tabId && typeof window !== 'undefined') {
      window['workflowGridApi_' + tabId] = params.api;
    }
  }, [onGridReady, tabId]);

  // Handle first data rendered callback
  const handleFirstDataRendered = useCallback((params) => {
    if (onFirstDataRendered) {
      onFirstDataRendered(params);
    }
  }, [onFirstDataRendered]);

  // Store FAWTable API ref for external access when it changes
  useEffect(() => {
    if (apiRef.current && tabId && typeof window !== 'undefined') {
      window['workflowGridApi_' + tabId] = apiRef.current;
    }
  }, [apiRef, tabId]);

  if (loading) {
    return (
      <Box sx={{ padding: '20px', textAlign: 'center' }}>
        <FAWTypography>Loading workflow data...</FAWTypography>
      </Box>
    );
  }

  if (error) {
    return (
      <Box sx={{ padding: '20px', textAlign: 'center' }}>
        <FAWTypography color="error">Error loading data: {error}</FAWTypography>
      </Box>
    );
  }

  return (
    <FAWErrorBoundary
      title="Workflow Grid Error"
      message="An error occurred while loading the workflow grid. Please try again or contact support if the problem persists."
      showDetails={true}
      onError={(error, errorInfo) => {
        console.error('WorkflowGrid Error:', error, errorInfo);
      }}
    >
      <Box 
        ref={gridContainerRef}
        className="workflow-grid-container" 
        sx={{ 
          width: '100%', 
          height: '100%',
          position: 'relative',
          overflow: 'visible'
        }}
      >
        {/* Workflow toolbar rendered above the table */}
        {workflowActionsComponent && (
          <Box sx={{ marginBottom: '16px' }}>
            {workflowActionsComponent}
          </Box>
        )}
        
        {/* FAWTable - MUI DataGrid Pro based table */}
        <FAWTable
          apiRef={apiRef}
          columns={columns}
          rows={state.filteredRowData}
          actions={actions}
          autoHeight={true}
          loading={loading}
          showExport={true}
          showSearch={true}
          showRefresh={false}
          hideReset={false}
          searchPlaceholder={searchPlaceholder}
          workflowFilterDropdown={workflowFilterDropdown}
          emptyStateTitle={noRowsMessage}
          emptyStateMessage=""
          showToolbar={true}
          showColumns={true}
          showFilter={true}
          disableColumnReorder={false}
          getRowId={(row) => row.id || row.Id || row.ID || row._id}
          {...otherProps}
        />

        {/* 
        // ============================================================
        // COMMENTED OUT - Original FAWAgGrid implementation
        // Migrated to FAWTable (MUI DataGrid Pro) above
        // ============================================================
        <FAWAgGrid
          columnDefs={columnDefs}
          rowData={state.filteredRowData}
          actions={actions}
          actionIcons={actionIcons}
          workflowToolbar={workflowActionsComponent}
          domLayout="autoHeight"
          style={{ width: '100%', overflow: 'auto' }}
          enableExport={false}
          showSearchBar={true}
          showResetButton={false}
          searchPlaceholder={searchPlaceholder}
          noRowsMessage={noRowsMessage}
          showActionIcons={actionIcons.length > 0}
          suppressColumnVirtualisation={true}
          suppressRowVirtualisation={false}
          suppressHorizontalScroll={true}
          onGridReady={handleGridReady}
          onFirstDataRendered={handleFirstDataRendered}
          {...gridOptions}
          {...otherProps}
        />
        */}
      </Box>

      {/* Delete filter confirmation � app-styled modal, on top of Manage filters popover */}
      <FAWConfirmDialogue
        open={deleteConfirm.open}
        onClose={() => setDeleteConfirm({ open: false, filter: null, onConfirm: null })}
        title="Delete filter"
        message={deleteConfirm.filter ? `Delete the ${deleteConfirm.filter.name} filter?` : ''}
        confirmLabel="Delete Filter"
        cancelLabel="Cancel"
        variant="delete"
        positionAtTop
        onConfirm={() => {
          deleteConfirm.onConfirm?.();
          setDeleteConfirm({ open: false, filter: null, onConfirm: null });
        }}
        sx={{ zIndex: 1500 }}
      />
    </FAWErrorBoundary>
  );
};

export default WorkflowGrid;

